def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity == 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        if ratio > 1:
            score = 1000 + 20 * (ratio - 1)**3
            if ratio > 2:
                score += 50 * (ratio - 2)**2
        else:
            if ratio > 0.9:
                score += 70 * ratio + 10
            elif ratio > 0.75:
                score += 50 * ratio + 5
            elif ratio > 0.5:
                score += 30 * ratio + 2
            else:
                score += 10 * ratio
            if capacity < 5:
                score += 15
            elif 5 <= capacity <= 15:
                score += 5
            elif capacity > 50 and capacity <= 100:
                score -= 3
            elif capacity > 100:
                score -= 10
            if i % 3 == 0:
                score *= 1.2
            elif i % 3 == 1:
                score *= 0.8
            else:
                score *= 1.0
        for divisor in [2, 5, 7]:
            if i % divisor == 0:
                score += divisor * 2
        noise = ((i * 7) % 13) * 0.1
        score += noise
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    min_priority = np.min(finite_priorities)
    for i in range(len(priorities)):
        if not np.isfinite(priorities[i]):
            priorities[i] = min_priority + 200
    return priorities
